class Solution(object):
    def maxArrayValue(self, nums):
        # Scan right to left: greedily merge
        n = len(nums)
        cur = nums[n-1]
        for i in range(n-2, -1, -1):
            if nums[i] <= cur:
                cur += nums[i]
            else:
                cur = nums[i]
        return cur
